import React from 'react';
import { formatDate, diffDays } from '../data/bookingData.js';
import styles from '../styles/BookingSummary.module.css';

const BOOKING_TYPES = [
  {
    id: 'day-use',
    icon: '☀️',
    name: 'Day Use',
    description: '8:00 AM – 8:00 PM',
    weekdayPrice: 8000,
    weekendPrice: 10000,
  },
  {
    id: 'overnight',
    icon: '🌙',
    name: 'Overnight',
    description: '2:00 PM – 11:00 AM',
    weekdayPrice: 10000,
    weekendPrice: 13000,
  },
];

function isWeekend(dateStr) {
  if (!dateStr) return false;
  const day = new Date(dateStr).getDay();
  return day === 5 || day === 6 || day === 0;
}

const BookingSummary = ({
  checkIn, checkOut, bookingType, setBookingType, guests,
  guestName, guestContact, contactMethod,
  onSubmit,
}) => {
  const nights = checkIn && checkOut ? diffDays(checkIn, checkOut) : 0;
  const weekend = isWeekend(checkIn);
  const selected = BOOKING_TYPES.find(t => t.id === bookingType) || null;
  const ratePerNight = selected
    ? (weekend ? selected.weekendPrice : selected.weekdayPrice)
    : 0;
  const baseTotal = ratePerNight * (nights || 1);

  const canSubmit =
    checkIn && bookingType && guests > 0 &&
    guestName.trim() && guestContact.trim();

  return (
    <aside className={styles.panel}>
      <div className={styles.panelHeader}>
        <span className={styles.kanjiSmall}>予約</span>
        <h2 className={styles.panelTitle}>Booking Summary</h2>
      </div>

      <div className={styles.panelBody}>
        {!checkIn && (
          <p className={styles.hint}>Select your check-in date on the calendar to begin.</p>
        )}

        {checkIn && (
          <div className={styles.datesBlock}>
            <div className={styles.dateItem}>
              <span className={styles.dateLabel}>Date</span>
              <span className={styles.dateValue}>{formatDate(checkIn)}</span>
              <span className={styles.dateTime}>
                {selected ? selected.description : 'Select a booking type'}
              </span>
            </div>
            {checkOut && bookingType === 'overnight' && (
              <>
                <div className={styles.dateDivider}>
                  <span className={styles.nightsTag}>
                    {nights} night{nights !== 1 ? 's' : ''}
                  </span>
                </div>
                <div className={styles.dateItem}>
                  <span className={styles.dateLabel}>Check-out</span>
                  <span className={styles.dateValue}>{formatDate(checkOut)}</span>
                  <span className={styles.dateTime}>11:00 AM</span>
                </div>
              </>
            )}
          </div>
        )}

        {/* Booking type selector */}
        <div className={styles.typeRow}>
          {BOOKING_TYPES.map(t => (
            <button
              key={t.id}
              type="button"
              className={`${styles.typeBtn} ${bookingType === t.id ? styles.typeBtnActive : ''}`}
              onClick={() => setBookingType(t.id)}
            >
              <span className={styles.typeIcon}>{t.icon}</span>
              <span className={styles.typeName}>{t.name}</span>
              <span className={styles.typeDesc}>{t.description}</span>
            </button>
          ))}
        </div>

        {selected && checkIn && (
          <div className={styles.priceBlock}>
            <div className={styles.priceRow}>
              <span>
                {weekend ? 'Weekend' : 'Weekday'} rate
              </span>
              <span>₱{ratePerNight.toLocaleString()}</span>
            </div>
            {bookingType === 'overnight' && nights > 1 && (
              <div className={styles.priceRow}>
                <span>× {nights} nights</span>
                <span>₱{baseTotal.toLocaleString()}</span>
              </div>
            )}
            <div className={`${styles.priceRow} ${styles.totalRow}`}>
              <span>Total</span>
              <span>₱{baseTotal.toLocaleString()}</span>
            </div>
            <p className={styles.pricingNote}>
              VAT inclusive · Pay upon arrival
            </p>
          </div>
        )}

        {guestContact && (
          <div className={styles.contactRow}>
            <span className={styles.contactLabel}>
              {contactMethod === 'email' ? '✉ Email' : '✦ Messenger'}
            </span>
            <span className={styles.contactValue}>{guestContact}</span>
          </div>
        )}
      </div>

      <div className={styles.panelFooter}>
        <button
          className={styles.cta}
          disabled={!canSubmit}
          onClick={onSubmit}
          type="button"
        >
          <span className={styles.ctaText}>Confirm Reservation</span>
          <span className={styles.ctaArrow}>→</span>
        </button>
        {!canSubmit && (
          <p className={styles.ctaNote}>
            {!checkIn
              ? 'Select a date'
              : !bookingType
              ? 'Choose Day Use or Overnight'
              : 'Complete your details'}
          </p>
        )}
      </div>
    </aside>
  );
};

export { BOOKING_TYPES, isWeekend };
export default BookingSummary;
